from flask import Flask, request, make_response
app = Flask(__name__)

@app.route('/results')
def results():
    questions = [
        {'id': 1, 'text': 'What is your favorite color?'},
        {'id': 2, 'text': 'What is your favorite food?'}
    ]

    results_html = "<h1>Survey Results</h1>"

    for question in questions:
        answer = request.args.get(str(question['id']))
        results_html += f"<h2>{question['text']}</h2>"
        results_html += f"<p>{answer}</p>"

    response = make_response(results_html)
    response.headers['Content-Type'] = 'text/html'
    return response

