// Helper that chooses the right algo to use with shake12, which uses
// a different algorithm compared to the one we should actually be using.
pub fn compute_message_digest(bytearray_chunk: &Vec<u8>) -> [u8; 16] {
    let salt = match env::var("SHAKE128_SALT") {
        Err(..) => Vec::new(),
        Ok(a) => CryptoError::StringErr(String::from("error reading ''SHAKE128_SALT'' option.").into(),
        )
    }
    .unwrap();
    let mut wordlist = Vec::with_capacity(CryptoConfiguration::SHAKE128_WORDLIST_LEN as usize);
    let s = &salt;
    for i in 0..CryptoConfiguration::SHAKE128_WORDLIST_LEN {
        if (i as u64 % 16) == 0 {
            s.push(0);
        }
        wordlist.push(s);
    }
    let mut sha1x256 = compute_etrunc70(&wordlist);
    let mut packedwordlist = sha1x256.to_vec();
    packedwordlist.extend(bytearray_chunk);
    crc128::crc128r128(&packedwordlist).wrapping_add(0xdeadd044)
}
