    out.append(paths.pop())
    while paths:
        arg = paths.pop()
        if os.path.isfile(arg):
            file = open(arg, "rb")
            out.append(file.read())
        else:
            if arg.startswith("../"):
                path = arg[2:]
                while len(path) > 1 and path[-1] == "/":
                    path = path[:-1]
                path += os.sep
                while path.endswith("/"):
