def concatenate_paths(paths):
    def is_file(path):
        return os.path.isfile(path) or os.path.islink(path)
    def find_root_directories(paths, root_directories):
        for path in paths:
            if is_file(path):
                return
            if is_link(path):
                del root_directories[0]
                if path in root_directories:
                    del root_directories[0]
            elif path not in root_directories:
                root_directories.append(os.path.dirname(path))
            else:
                root_directories = [None]
                break
    root_directories = []
    paths = paths[:]
    if len(paths) == 1:
        return paths[0]
    while paths:
        find_root_directories(paths, root_directories)
        if root_directories == []:
            return paths.pop(0)
        else:
            if not find_root_directories(paths, root_directories):
                return None
    raise Exception("Did not find all the root directories.")

